import json
import os
import pymysql

# Database configuration from environment variables
DB_HOST = os.environ.get('DB_HOST', 'localhost')
DB_USER = os.environ.get('DB_USER', 'admin')
DB_PASSWORD = os.environ.get('DB_PASSWORD', 'password')
DB_NAME = os.environ.get('DB_NAME', 'products_db')
DB_PORT = int(os.environ.get('DB_PORT', 3306))

# Connection pooling - reuse connections across Lambda invocations
connection = None


def get_connection():
    """Get or create a database connection."""
    global connection
    if connection is None or not connection.open:
        connection = pymysql.connect(
            host=DB_HOST,
            user=DB_USER,
            password=DB_PASSWORD,
            database=DB_NAME,
            port=DB_PORT,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=5,
            read_timeout=10,
            write_timeout=10,
            autocommit=True
        )
    return connection


def build_search_query(params):
    """
    Dynamically build SQL query based on search parameters.
    
    Supported parameters:
    - keyword: Search in product name and description
    - category: Filter by category (exact match)
    - category_id: Filter by category ID
    - min_price: Minimum price filter
    - max_price: Maximum price filter
    - brand: Filter by brand name
    - in_stock: Filter by stock availability (true/false)
    - min_rating: Minimum rating filter
    - tags: Comma-separated tags to filter by
    - sort_by: Field to sort by (name, price, rating, created_at)
    - sort_order: ASC or DESC
    - page: Page number for pagination (1-based)
    - page_size: Number of results per page (default 20, max 100)
    """
    base_query = "SELECT * FROM products"
    count_query = "SELECT COUNT(*) as total FROM products"
    conditions = []
    values = []

    # Keyword search in name and description
    if params.get('keyword'):
        keyword = params['keyword'].strip()
        conditions.append("(name LIKE %s OR description LIKE %s)")
        keyword_pattern = f"%{keyword}%"
        values.extend([keyword_pattern, keyword_pattern])

    # Category filter (exact match)
    if params.get('category'):
        conditions.append("category = %s")
        values.append(params['category'].strip())

    # Category ID filter
    if params.get('category_id'):
        try:
            category_id = int(params['category_id'])
            conditions.append("category_id = %s")
            values.append(category_id)
        except (ValueError, TypeError):
            pass

    # Price range filters
    if params.get('min_price'):
        try:
            min_price = float(params['min_price'])
            conditions.append("price >= %s")
            values.append(min_price)
        except (ValueError, TypeError):
            pass

    if params.get('max_price'):
        try:
            max_price = float(params['max_price'])
            conditions.append("price <= %s")
            values.append(max_price)
        except (ValueError, TypeError):
            pass

    # Brand filter
    if params.get('brand'):
        conditions.append("brand = %s")
        values.append(params['brand'].strip())

    # Stock availability filter
    if params.get('in_stock') is not None:
        in_stock = str(params['in_stock']).lower()
        if in_stock in ('true', '1', 'yes'):
            conditions.append("stock_quantity > 0")
        elif in_stock in ('false', '0', 'no'):
            conditions.append("stock_quantity = 0")

    # Minimum rating filter
    if params.get('min_rating'):
        try:
            min_rating = float(params['min_rating'])
            if 0 <= min_rating <= 5:
                conditions.append("rating >= %s")
                values.append(min_rating)
        except (ValueError, TypeError):
            pass

    # Tags filter (comma-separated)
    if params.get('tags'):
        tags = [tag.strip() for tag in params['tags'].split(',') if tag.strip()]
        if tags:
            tag_conditions = []
            for tag in tags:
                tag_conditions.append("FIND_IN_SET(%s, tags) > 0")
                values.append(tag)
            conditions.append(f"({' OR '.join(tag_conditions)})")

    # Active/enabled products only by default
    if params.get('include_inactive') is None or str(params.get('include_inactive')).lower() not in ('true', '1', 'yes'):
        conditions.append("is_active = 1")

    # Build WHERE clause
    where_clause = ""
    if conditions:
        where_clause = " WHERE " + " AND ".join(conditions)

    # Sorting - whitelist allowed sort fields to prevent SQL injection
    allowed_sort_fields = {
        'name': 'name',
        'price': 'price',
        'rating': 'rating',
        'created_at': 'created_at',
        'updated_at': 'updated_at',
        'stock_quantity': 'stock_quantity',
        'brand': 'brand'
    }
    
    sort_by = params.get('sort_by', 'created_at')
    sort_field = allowed_sort_fields.get(sort_by, 'created_at')
    
    sort_order = params.get('sort_order', 'DESC').upper()
    if sort_order not in ('ASC', 'DESC'):
        sort_order = 'DESC'

    order_clause = f" ORDER BY {sort_field} {sort_order}"

    # Pagination
    try:
        page = max(1, int(params.get('page', 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(100, max(1, int(params.get('page_size', 20))))
    except (ValueError, TypeError):
        page_size = 20

    offset = (page - 1) * page_size
    limit_clause = f" LIMIT %s OFFSET %s"

    # Assemble final queries
    final_count_query = count_query + where_clause
    count_values = list(values)  # Copy values for count query

    final_query = base_query + where_clause + order_clause + limit_clause
    values.extend([page_size, offset])

    return {
        'query': final_query,
        'count_query': final_count_query,
        'values': values,
        'count_values': count_values,
        'page': page,
        'page_size': page_size
    }


def extract_params(event):
    """Extract search parameters from API Gateway event."""
    params = {}
    
    # GET request - parameters from query string
    if event.get('queryStringParameters'):
        params.update(event['queryStringParameters'])
    
    # Handle multi-value query string parameters
    if event.get('multiValueQueryStringParameters'):
        for key, value_list in event['multiValueQueryStringParameters'].items():
            if len(value_list) > 1:
                params[key] = ','.join(value_list)
    
    # POST request - parameters from body
    if event.get('body'):
        try:
            body = event['body']
            if isinstance(body, str):
                body = json.loads(body)
            params.update(body)
        except (json.JSONDecodeError, TypeError):
            pass
    
    # Path parameters
    if event.get('pathParameters'):
        params.update(event['pathParameters'])
    
    return params


def format_product(product):
    """Format product data for JSON serialization."""
    formatted = {}
    for key, value in product.items():
        if hasattr(value, 'isoformat'):
            formatted[key] = value.isoformat()
        elif isinstance(value, bytes):
            formatted[key] = value.decode('utf-8')
        else:
            formatted[key] = value
    return formatted


def create_response(status_code, body, headers=None):
    """Create a properly formatted API Gateway response."""
    response = {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type,Authorization',
            'Access-Control-Allow-Methods': 'GET,POST,OPTIONS'
        },
        'body': json.dumps(body, default=str)
    }
    if headers:
        response['headers'].update(headers)
    return response


def lambda_handler(event, context):
    """
    Main Lambda handler for product search.
    
    Receives search parameters via API Gateway event and returns
    matching products from the RDS MySQL database.
    """
    # Handle CORS preflight
    http_method = event.get('httpMethod', event.get('requestContext', {}).get('http', {}).get('method', ''))
    if http_method == 'OPTIONS':
        return create_response(200, {'message': 'OK'})

    try:
        # Extract search parameters
        params = extract_params(event)
        
        # Build the dynamic query
        query_data = build_search_query(params)
        
        # Execute the queries
        conn = get_connection()
        
        try:
            with conn.cursor() as cursor:
                # Get total count
                cursor.execute(query_data['count_query'], query_data['count_values'])
                count_result = cursor.fetchone()
                total_count = count_result['total'] if count_result else 0
                
                # Get paginated results
                cursor.execute(query_data['query'], query_data['values'])
                products = cursor.fetchall()
        except pymysql.OperationalError as e:
            # Connection might have been closed, retry once
            global connection
            connection = None
            conn = get_connection()
            with conn.cursor() as cursor:
                cursor.execute(query_data['count_query'], query_data['count_values'])
                count_result = cursor.fetchone()
                total_count = count_result['total'] if count_result else 0
                
                cursor.execute(query_data['query'], query_data['values'])
                products = cursor.fetchall()

        # Format products for JSON serialization
        formatted_products = [format_product(p) for p in products]
        
        # Calculate pagination metadata
        page = query_data['page']
        page_size = query_data['page_size']
        total_pages = (total_count + page_size - 1) // page_size if total_count > 0 else 0
        
        response_body = {
            'success': True,
            'data': {
                'products': formatted_products,
                'pagination': {
                    'page': page,
                    'page_size': page_size,
                    'total_count': total_count,
                    'total_pages': total_pages,
                    'has_next': page < total_pages,
                    'has_previous': page > 1
                }
            },
            'search_params': {k: v for k, v in params.items() if v is not None}
        }
        
        return create_response(200, response_body)
    
    except pymysql.MySQLError as e:
        error_code = e.args[0] if e.args else 'Unknown'
        error_message = e.args[1] if len(e.args) > 1 else str(e)
        
        print(f"Database error [{error_code}]: {error_message}")
        
        return create_response(500, {
            'success': False,
            'error': 'Database error occurred',
            'message': 'Unable to process your search request. Please try again later.'
        })
    
    except json.JSONDecodeError as e:
        return create_response(400, {
            'success': False,
            'error': 'Invalid JSON',
            'message': f'The request body contains invalid JSON: {str(e)}'
        })
    
    except Exception as e:
        print(f"Unexpected error: {type(e).__name__}: {str(e)}")
        
        return create_response(500, {
            'success': False,
            'error': 'Internal server error',
            'message': 'An unexpected error occurred. Please try again later.'
        })